"use client";


import axios from "axios";
import { useEffect, useState } from "react";

type Product = {
    product_id: number | string;
    product_name: string;
    category: string;
    price: number;
    stock_quantity: number;
    image_url: string;
};

export default function ProductCard() {
    const [products, setProducts] = useState<Product[]>([]);
    const [isLoading, setIsLoading] = useState(true);

    useEffect(() => {
        const fetchProducts = async () => {
            try {
                const response = await axios.get(`${process.env.NEXT_PUBLIC_API_BASE_URL}/products`);
                const formattedData: Product[] = response.data.map((item: any) => ({
                    product_id: item.productid,
                    product_name: item.productname,
                    category: item.category,
                    price: Number(item.price),
                    stock_quantity: Number(item.stockquantity),
                    image_url: item.imageurl,
                }));

                setProducts(formattedData);
            } catch (error) {
                console.error("哎呀！商品搬運失敗:", error);
            } finally {
                setIsLoading(false);
            }
        };

        fetchProducts();
    }, []);

    if (isLoading) {
        return <p className="text-sm text-retro-slate">商品載入中...</p>;
    }

    if (products.length === 0) {
        return <p className="text-sm text-retro-slate">目前沒有商品資料</p>;
    }

    return (
        <section>
            <h2 className="text-xl font-semibold text-retro-ink mb-4">商品清單</h2>
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                {products.map((product) => (
                    <article key={product.product_id} className="rounded-xl border border-white/50 bg-white/60 p-4">
                        <p className="text-base font-bold text-retro-ink">{product.product_name}</p>
                        <p className="text-sm text-retro-slate mt-1">分類：{product.category}</p>
                        <p className="text-sm text-retro-slate">庫存：{product.stock_quantity}</p>
                        <p className="text-sm font-semibold text-retro-ink mt-2">價格：${product.price}</p>
                    </article>
                ))}
            </div>
        </section>
    );
}